48: void IonCompileTask::runTask() {
49:   // This is the entry point when ion compiles are run offthread.
50: 
51:   jit::JitContext jctx(mirGen_.realm->runtime());
52:   setBackgroundCodegen(jit::CompileBackEnd(&mirGen_, snapshot_));
53: }
