57: static bool CheckFrame(InterpreterFrame* fp) {
58:   if (fp->isDebuggerEvalFrame()) {
59:     // Debugger eval-in-frame. These are likely short-running scripts so
60:     // don't bother compiling them for now.
61:     JitSpew(JitSpew_BaselineAbort, "debugger frame");
62:     return false;
63:   }
64: 
65:   if (fp->isFunctionFrame() && TooManyActualArguments(fp->numActualArgs())) {
66:     // Fall back to the interpreter to avoid running out of stack space.
67:     JitSpew(JitSpew_BaselineAbort, "Too many arguments (%u)",
68:             fp->numActualArgs());
69:     return false;
70:   }
71: 
72:   return true;
73: }
